@@ -0,0 +1,45 @@
+package net.sf.mpxj.util;
+
+import java.io.File;
+import java.io.IOException;
+
+/**
+ * Utility class for validating file paths to prevent path traversal attacks.
+ */
+public class PathValidator {
+
+    /**
+     * Validates that a file path is within the expected base directory.
+     *
+     * @param basePath the base directory path
+     * @param relativePath the relative path to validate
+     * @return true if the path is safe, false otherwise
+     */
+    public static boolean isPathSafe(String basePath, String relativePath) {
+        if (basePath == null || relativePath == null) {
+            return false;
+        }
+
+        try {
+            File baseDir = new File(basePath).getCanonicalFile();
+            File targetFile = new File(baseDir, relativePath).getCanonicalFile();
+
+            String canonicalBase = baseDir.getCanonicalPath();
+            String canonicalTarget = targetFile.getCanonicalPath();
+
+            // Ensure the target path starts with the base directory path
+            return canonicalTarget.startsWith(canonicalBase + File.separator)
+                    || canonicalTarget.equals(canonicalBase);
+        } catch (IOException e) {
+            // If we can't resolve the path, treat it as unsafe
+            return false;
+        }
+    }
+}
