+/**
+ * Validates that a URL is a trusted Firebase domain to prevent SSRF attacks
+ * via the FIREBASE_DEFAULTS cookie.
+ */
+export function isTrustedFirebaseUrl(url: string): boolean {
+  try {
+    const parsedUrl = new URL(url);
+
+    // Only allow HTTPS scheme
+    if (parsedUrl.protocol !== 'https:') {
+      return false;
+    }
+
+    // Whitelist trusted Firebase domains
+    const trustedDomains = [
+      'firebaseio.com',
+      'googleapis.com',
+      'google.com'
+    ];
+
+    return trustedDomains.some(domain => parsedUrl.hostname.endsWith(domain));
+  } catch {
+    return false;
+  }
+}

