+    }
+    
+    // Verify root certificate is trusted (self-signed)
+    let (_, root_cert) = parse_x509_certificate(&cert_chain[0])
+        .map_err(|e| Error::InvalidCertificateChain(format!("Failed to parse root certificate: {}", e)))?;
+    
