+// CVE-2026-25752: Add authorization middleware
+
+'use strict';
+
+function hasPermission(permission) {
+  if (!this.user) return false;
+  if (!this.user.permissions) return false;
+  return this.user.permissions.includes(permission);
+}
+
+function hasDeviceAccess(deviceId, action) {
+  if (!this.user) return false;
+  if (!this.user.deviceAccess) return false;
+  return this.user.deviceAccess.some(
+    d => d.deviceId === deviceId && d.action === action
+  );
+}
+
+function verifyRole(requiredRole) {
+  if (!this.user) return false;
+  if (!this.user.role) return false;
+  return this.user.role === requiredRole;
+}
+
+module.exports = {
+  hasPermission,
+  hasDeviceAccess,
+  verifyRole
+};
